import java.util.Scanner;
import parsing.BoardParser;
import parsing.BoardValidator;

/**
 * Main entry point.
 * Orchestrates parsing, validation, and command execution.
 * This file remains constant across all iterations.
 */
public class Main {
    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);

        // Iteration 1: Parse and validate board
        BoardParser parser = new BoardParser();
        String[][] board = parser.readBoard(input);

        if (!BoardValidator.isValid(board)) {
            input.close();
            return;
        }

        // Process commands
        while (input.hasNextLine()) {
            String command = input.nextLine().trim();

            if (command.isEmpty()) {
                continue;
            }

            if (command.equals("print board")) {
                BoardValidator.printBoard(board);
            }
            // Future iterations: add more command handlers here
        }

        input.close();
    }
}

import java.util.Scanner;
import java.util.ArrayList;

/**
 * Main entry point.
 * Orchestrates parsing, validation, and command execution.
 * This file remains constant across all iterations.
 */
public class Main {
    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);

        // Iteration 1: Parse and validate board
        BoardParser parser = new BoardParser();
        String[][] board = parser.readBoard(input);

        if (!BoardValidator.isValid(board)) {
            input.close();
            return;
        }

        // Process commands
        while (input.hasNextLine()) {
            String command = input.nextLine().trim();

            if (command.isEmpty()) {
                continue;
            }

            if (command.equals("print board")) {
                BoardValidator.printBoard(board);
            }
            // Future iterations: add more command handlers here
        }

        input.close();
    }

    /**
     * Parses board fixture from standard input.
     */
    static class BoardParser {
        private static final String BOARD_MARKER = "Board:";
        private static final String COMMANDS_MARKER = "Commands:";
        private static final String WHITESPACE = "\\s+";

        String[][] readBoard(Scanner input) {
            ArrayList<String> rows = new ArrayList<>();
            int expectedWidth = -1;
            boolean parsingBoard = false;

            while (input.hasNextLine()) {
                String line = input.nextLine().trim();

                if (line.isEmpty()) {
                    continue;
                }

                if (line.equals(BOARD_MARKER)) {
                    parsingBoard = true;
                    continue;
                }

                if (line.equals(COMMANDS_MARKER)) {
                    break;
                }

                if (parsingBoard) {
                    String[] tokens = line.split(WHITESPACE);

                    // Check width consistency
                    if (expectedWidth == -1) {
                        expectedWidth = tokens.length;
                    } else if (tokens.length != expectedWidth) {
                        System.out.println("ERROR ROW_WIDTH_MISMATCH");
                        return new String[0][0];
                    }

                    rows.add(line);
                }
            }

            return buildMatrix(rows, expectedWidth);
        }

        private String[][] buildMatrix(ArrayList<String> rows, int width) {
            if (rows.isEmpty() || width <= 0) {
                return new String[0][0];
            }

            String[][] matrix = new String[rows.size()][width];
            for (int i = 0; i < rows.size(); i++) {
                matrix[i] = rows.get(i).split(WHITESPACE);
            }
            return matrix;
        }
    }

    /**
     * Validates board structure and tokens.
     */
    static class BoardValidator {
        private static final String TOKEN_PATTERN = "\\.|[wb][KQRBNP]";

        static boolean isValid(String[][] board) {
            if (board == null || board.length == 0) {
                return false;
            }

            for (String[] row : board) {
                for (String token : row) {
                    if (!token.matches(TOKEN_PATTERN)) {
                        System.out.println("ERROR UNKNOWN_TOKEN");
                        return false;
                    }
                }
            }

            return true;
        }

        static void printBoard(String[][] board) {
            if (board == null || board.length == 0) {
                return;
            }

            for (int row = 0; row < board.length; row++) {
                for (int col = 0; col < board[row].length; col++) {
                    System.out.print(board[row][col]);
                    if (col < board[row].length - 1) {
                        System.out.print(" ");
                    }
                }
                System.out.println();
            }
        }
    }
}
